var resp = $('최상위 블록').first().json;
var results = (resp && resp.results) || [];
var ids = [];
for (var i = 0; i < results.length; i++) {
  var b = results[i];
  if (b && b.has_children && b.type !== 'child_database') ids.push(b.id);
}
if (ids.length === 0) return [{ json: { childId: '' } }];
return ids.map(function (id) { return { json: { childId: id } }; });

var resp = $('최상위 블록').first().json;
var results = (resp && resp.results) || [];
var ids = [];
for (var i = 0; i < results.length; i++) {
  var b = results[i];
  if (b && b.type === 'child_database') ids.push(b.id);
}
if (ids.length === 0) return [{ json: { dbId: '' } }];
return ids.map(function (id) { return { json: { dbId: id } }; });

function richText(arr) {
  if (!Array.isArray(arr)) return '';
  var s = '';
  for (var i = 0; i < arr.length; i++) {
    var t = arr[i]; if (!t) continue;
    s += (t.plain_text || (t.text && t.text.content) || '');
  }
  return s;
}
function plainTitle(arr){ return richText(arr); }
function propVal(p) {
  if (!p) return '';
  var t = p.type;
  if (t === 'title') return richText(p.title);
  if (t === 'rich_text') return richText(p.rich_text);
  if (t === 'select') return (p.select && p.select.name) || '';
  if (t === 'status') return (p.status && p.status.name) || '';
  if (t === 'multi_select') return (p.multi_select || []).map(function (o) { return o.name; }).join(', ');
  if (t === 'number') return (p.number != null) ? String(p.number) : '';
  if (t === 'checkbox') return p.checkbox ? '예' : '아니오';
  if (t === 'date') return (p.date && p.date.start) ? (p.date.start + (p.date.end ? (' ~ ' + p.date.end) : '')) : '';
  if (t === 'url') return p.url || '';
  if (t === 'email') return p.email || '';
  if (t === 'phone_number') return p.phone_number || '';
  if (t === 'people') return (p.people || []).map(function (u) { return (u && (u.name || u.id)) || ''; }).join(', ');
  if (t === 'files') return (p.files || []).map(function (f) { return f.name || ''; }).join(', ');
  if (t === 'formula') { var f = p.formula || {}; return String(f.string != null ? f.string : (f.number != null ? f.number : (f.boolean != null ? f.boolean : ''))); }
  if (t === 'created_time') return p.created_time || '';
  if (t === 'last_edited_time') return p.last_edited_time || '';
  return '';
}
function renderRows(rows) {
  var out = [];
  for (var i = 0; i < rows.length; i++) {
    var pg = rows[i]; if (!pg || !pg.properties) continue;
    var props = pg.properties;
    var titleKey = null;
    for (var k in props) { if (props[k] && props[k].type === 'title') { titleKey = k; break; } }
    var head = titleKey ? propVal(props[titleKey]) : '';
    out.push('• ' + (head || ('항목 ' + (i + 1))));
    var parts = [];
    for (var k2 in props) {
      if (k2 === titleKey) continue;
      var v = propVal(props[k2]);
      if (v && String(v).trim()) parts.push('   - ' + k2 + ': ' + String(v).replace(/\n/g, ' '));
    }
    if (parts.length) out.push(parts.join('\n'));
  }
  return out.join('\n');
}

var REFS = [];
function addRef(id, title) { if (id) REFS.push({ id: id, title: title || '' }); }
function scanMentions(arr) {
  if (!Array.isArray(arr)) return;
  for (var i = 0; i < arr.length; i++) {
    var t = arr[i]; if (!t || t.type !== 'mention' || !t.mention) continue;
    var m = t.mention;
    if (m.type === 'page' && m.page && m.page.id) addRef(m.page.id, t.plain_text);
    else if (m.type === 'database' && m.database && m.database.id) addRef(m.database.id, t.plain_text);
  }
}

function renderBlock(b, childMap, dbMap) {
  if (!b) return '';
  var t = b.type;
  if (b[t] && b[t].rich_text) scanMentions(b[t].rich_text);
  var rt = (b[t] && b[t].rich_text) ? richText(b[t].rich_text) : '';
  if (t === 'heading_1') return '# ' + rt;
  if (t === 'heading_2') return '## ' + rt;
  if (t === 'heading_3') return '### ' + rt;
  if (t === 'paragraph') return rt;
  if (t === 'bulleted_list_item') return '- ' + rt;
  if (t === 'numbered_list_item') return '1. ' + rt;
  if (t === 'to_do') { var ck = (b.to_do && b.to_do.checked) ? '[x]' : '[ ]'; return '- ' + ck + ' ' + rt; }
  if (t === 'quote') return '> ' + rt;
  if (t === 'callout') { var ic = (b.callout && b.callout.icon && b.callout.icon.emoji) ? (b.callout.icon.emoji + ' ') : ''; return '> ' + ic + rt; }
  if (t === 'toggle') return '- ' + rt;
  if (t === 'code') return '[code] ' + rt;
  if (t === 'divider') return '---';
  if (t === 'child_page') { addRef(b.id, (b.child_page && b.child_page.title) || ''); return '[참조 하위 페이지: ' + ((b.child_page && b.child_page.title) || '') + ' / id:' + b.id + ']'; }
  if (t === 'link_to_page') { var lid = (b.link_to_page && (b.link_to_page.page_id || b.link_to_page.database_id)) || ''; addRef(lid, ''); return '[참조 링크 페이지 / id:' + lid + ']'; }
  if (t === 'child_database') {
    var rows = dbMap[b.id] || [];
    var title = (b.child_database && b.child_database.title) || 'DB';
    var body = renderRows(rows);
    return '### [표 데이터: ' + title + ']\n' + (body || '[행 없음 또는 접근불가]');
  }
  if (t === 'image' || t === 'file' || t === 'video' || t === 'embed' || t === 'bookmark') return '[' + t + ']';
  if (t === 'table_of_contents') return '';
  if (t === 'table') {
    var rows2 = childMap[b.id] || [];
    var out = [];
    for (var r = 0; r < rows2.length; r++) {
      var row = rows2[r];
      if (row && row.type === 'table_row' && row.table_row && Array.isArray(row.table_row.cells)) {
        var cells = row.table_row.cells.map(function (c) { return richText(c).replace(/\n/g, ' '); });
        out.push('| ' + cells.join(' | ') + ' |');
      }
    }
    return out.join('\n');
  }
  return rt;
}

var top = $('최상위 블록').first().json;
if (!top || !top.results) {
  var code = (top && (top.code || top.status)) || 'unknown';
  var msg = (top && top.message) || '';
  return [{ json: { text: '[읽기 실패] 이 Notion 페이지/블록에 접근할 수 없습니다 (code: ' + code + '). ' + msg + ' → Overmind 통합에 해당 페이지 공유가 필요합니다.', refs: [], ok: false } }];
}
// 블록 자식 맵 (has_children)
var childItems = $('자식 id 추출').all();
var childResps = $('자식 블록').all();
var childMap = {};
for (var i = 0; i < childItems.length; i++) {
  var cid = childItems[i].json.childId;
  var rr = (childResps[i] && childResps[i].json && childResps[i].json.results) || [];
  if (cid) childMap[cid] = rr;
}
// DB 행 맵 (child_database)
var dbItems = $('DB id 추출').all();
var dbResps = $('DB 행 조회').all();
var dbMap = {};
for (var di = 0; di < dbItems.length; di++) {
  var did = dbItems[di].json.dbId;
  var dr = (dbResps[di] && dbResps[di].json && dbResps[di].json.results) || [];
  if (did) dbMap[did] = dr;
}
var lines = [];
var blocks = top.results;
for (var j = 0; j < blocks.length; j++) {
  var b = blocks[j];
  var line = renderBlock(b, childMap, dbMap);
  if (line && line.length) lines.push(line);
  if (b && b.has_children && b.type !== 'table' && b.type !== 'child_database') {
    var kids = childMap[b.id] || [];
    for (var k = 0; k < kids.length; k++) {
      var kl = renderBlock(kids[k], childMap, dbMap);
      if (kl && kl.length) lines.push('    ' + kl);
    }
  }
}
var md = lines.join('\n');
if (!md) md = '[본문 없음]';
// refs 중복 제거
var seen = {}; var uref = [];
for (var x = 0; x < REFS.length; x++) { var rid = REFS[x].id; if (rid && !seen[rid]) { seen[rid] = 1; uref.push(REFS[x]); } }
if (uref.length) {
  md += '\n\n📎 이 문서가 참조하는 다른 Notion 페이지(필요하다고 판단되면 읽기 툴로 직접 열람): '
      + uref.map(function (r) { return (r.title ? (r.title + ' ') : '') + '(id:' + r.id + ')'; }).join(', ');
}
return [{ json: { text: md, refs: uref, ok: true } }];
